import boto3

def publish_sqs_message(queue_url, message_body):
    # Create an SQS client using boto3
    sqs = boto3.client('sqs')

    # Send a message to the specified SQS queue
    response = sqs.send_message(
        QueueUrl=queue_url,
        MessageBody=message_body
    )

    return response

